// â”€â”€ Node 3: Validate Payload â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Accepts Evolution API webhook payload, filters out non-message events,
// fromMe=true, group messages, and missing required fields.

const body = ($input.first().json.body !== undefined)
  ? $input.first().json.body
  : $input.first().json;

const eventType = (body.event || body.type || '').toLowerCase();
const validPrefixes = ['messages.upsert', 'message_received', 'message'];
const isValidEvent = validPrefixes.some(function(p) { return eventType.includes(p); });

if (!isValidEvent) {
  return [{ json: { valid: false, reason: 'not_message_event', event_type: eventType } }];
}

const data  = body.data || body;
const key   = data.key || (data.message && data.message.key) || {};
const msg   = data.message || data;

if (key.fromMe === true) {
  return [{ json: { valid: false, reason: 'from_me' } }];
}

const remoteJid         = key.remoteJid  || '';
const instanceName      = body.instance  || body.instanceName || '';
const externalMessageId = key.id         || '';

if (!remoteJid || !instanceName || !externalMessageId) {
  return [{ json: { valid: false, reason: 'missing_required_fields' } }];
}

// Skip group messages â€” remove this block if you want to handle groups
if (remoteJid.endsWith('@g.us')) {
  return [{ json: { valid: false, reason: 'group_message_skipped' } }];
}

const contactIdentifier = remoteJid.replace(/@.*$/, '');

let contentType = 'text';
let contentText = null;
let mediaUrl    = null;
let caption     = null;

if (msg.conversation) {
  contentText = msg.conversation;
} else if (msg.extendedTextMessage && msg.extendedTextMessage.text) {
  contentText = msg.extendedTextMessage.text;
} else if (msg.imageMessage) {
  contentType = 'image';
  mediaUrl    = msg.imageMessage.url     || null;
  caption     = msg.imageMessage.caption || null;
} else if (msg.audioMessage) {
  contentType = 'audio';
  mediaUrl    = msg.audioMessage.url || null;
} else if (msg.documentMessage) {
  contentType = 'document';
  mediaUrl    = msg.documentMessage.url   || null;
  caption     = msg.documentMessage.title || null;
} else if (msg.videoMessage) {
  contentType = 'video';
  mediaUrl    = msg.videoMessage.url     || null;
  caption     = msg.videoMessage.caption || null;
} else {
  contentType = 'unknown';
}

const contactName = data.pushName || data.notifyName || null;
const ts          = data.messageTimestamp;
const sentAt      = ts ? new Date(Number(ts) * 1000).toISOString() : new Date().toISOString();

return [{
  json: {
    valid:                true,
    instance_name:        instanceName,
    external_message_id:  externalMessageId,
    contact_identifier:   contactIdentifier,
    contact_name:         contactName,
    contact_jid:          remoteJid,
    content_type:         contentType,
    content_text:         contentText,
    media_url:            mediaUrl,
    caption:              caption,
    sent_at:              sentAt,
    raw_body:             body
  }
}];

// â”€â”€ Node 6: Extract Connection â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// PostgREST returns an array. Extract the first row or flag as not found.

const items = $input.all();
let connection = null;

for (var i = 0; i < items.length; i++) {
  var item = items[i].json;
  if (Array.isArray(item) && item.length > 0) {
    connection = item[0];
    break;
  } else if (item && item.id) {
    connection = item;
    break;
  }
}

if (!connection || !connection.id || !connection.company_id) {
  return [{ json: { found: false } }];
}

return [{
  json: {
    found:       true,
    id:          connection.id,
    company_id:  connection.company_id,
    owner_id:    connection.owner_id || null,
    channel:     connection.channel,
    external_id: connection.external_id
  }
}];

// â”€â”€ Node 8: Normalize to Canonical Event â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Merges validated payload + connection data into the canonical event JSON.
// Optionally validates HMAC signature if EVOLUTION_WEBHOOK_SECRET is set.

const validated = $('Code - Validate Payload').first().json;
const conn      = $input.first().json;

// â”€â”€ Optional HMAC validation â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const secret = '';
if (secret) {
  let headers = {};
  try { headers = $('Webhook Trigger').first().json.headers || {}; } catch(e) {}
  const sig = headers['x-evolution-signature'] || headers['x-hub-signature-256'] || '';
  if (!sig) {
    throw new Error('HMAC secret configured but no signature header received');
  }
  const crypto   = require('crypto');
  const rawBody  = JSON.stringify(validated.raw_body);
  const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');
  if (sig !== expected) {
    throw new Error('Invalid webhook signature â€” possible spoofed request');
  }
}

const canonicalEvent = {
  event_id:              validated.external_message_id + '_' + conn.company_id,
  source:                'evolution_api',
  channel:               'whatsapp',
  instance_name:         validated.instance_name,
  channel_connection_id: conn.id,
  company_id:            conn.company_id,
  owner_id:              conn.owner_id || null,
  direction:             'inbound',
  external_message_id:   validated.external_message_id,
  contact_identifier:    validated.contact_identifier,
  contact_name:          validated.contact_name,
  contact_jid:           validated.contact_jid,
  content_type:          validated.content_type,
  content_text:          validated.content_text,
  media_url:             validated.media_url,
  caption:               validated.caption,
  sent_at:               validated.sent_at,
  raw_payload:           validated.raw_body
};

return [{ json: canonicalEvent }];

// V19 — data URL direto do base64 do webhook (sem HTTP, sem require)
// base64 já vem no payload da Evolution API — converte para data: URL
// Browser toca/exibe data URLs nativamente

const canonical = $input.first().json;

const mediaTypes = ['image', 'audio', 'video', 'document'];
if (!mediaTypes.includes(canonical.content_type)) {
  return [{ json: canonical }];
}

const rawData = canonical.raw_payload.data || canonical.raw_payload;
const msg = rawData.message || {};
const mediaMsg = msg[canonical.content_type + 'Message'] || {};

// base64 pode estar em msg.base64 (nível raiz) ou dentro do objeto de mídia
const b64 = msg.base64 || mediaMsg.base64;

if (!b64) {
  return [{ json: canonical }];
}

const mimeRaw = mediaMsg.mimetype || (canonical.content_type === 'image' ? 'image/jpeg' : canonical.content_type === 'audio' ? 'audio/ogg' : 'application/octet-stream');
const mime = mimeRaw.split(';')[0].trim();
const dataUrl = `data:${mime};base64,${b64}`;

return [{ json: { ...canonical, media_url: dataUrl } }];

// â”€â”€ Node 10: Check Duplicate â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// PostgREST with resolution=ignore-duplicates returns [] on conflict.
// If result is empty â†’ duplicate â†’ stop pipeline.

const items = $input.all();
let isDuplicate = true;

for (var i = 0; i < items.length; i++) {
  var item = items[i].json;
  if (Array.isArray(item) && item.length > 0) {
    isDuplicate = false;
    break;
  } else if (item && item.id) {
    isDuplicate = false;
    break;
  }
}

// Pass the canonical event forward together with the duplicate flag
const canonical = $('Code - Normalize to Canonical Event').first().json;

return [{ json: Object.assign({}, canonical, { is_duplicate: isDuplicate }) }];

